import React, { useEffect, useState } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";

function App() {
  const [jobs, setJobs] = useState([]);
  const [applications, setApplications] = useState([]);
  const [email, setEmail] = useState("test@test.com");
  const [password, setPassword] = useState("Test123!");
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [showApplications, setShowApplications] = useState(false);

  const apiUrl = "https://localhost:7059/api";

  useEffect(() => {
    loadJobs();
  }, []);

  const loadJobs = async () => {
    try {
      const response = await axios.get(`${apiUrl}/Jobs`);
      setJobs(response.data);
    } catch (error) {
      console.error(error);
    }
  };

  const login = async () => {
    try {
      const response = await axios.post(`${apiUrl}/Auth/login`, {
        email,
        password,
      });

      localStorage.setItem("token", response.data.token);
      setIsLoggedIn(true);
    } catch (error) {
      console.error(error);
      alert("Login failed");
    }
  };

  const logout = () => {
    localStorage.removeItem("token");
    setIsLoggedIn(false);
    setShowApplications(false);
  };

  const applyToJob = async (jobId) => {
    try {
      const token = localStorage.getItem("token");

      await axios.post(
        `${apiUrl}/Applications`,
        { jobId: jobId },
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      );

      alert("Application sent!");
      loadApplications();
    } catch (error) {
      console.error(error);
      alert("Could not apply");
    }
  };

  const loadApplications = async () => {
    try {
      const response = await axios.get(`${apiUrl}/Applications`);
      setApplications(response.data);
      setShowApplications(true);
    } catch (error) {
      console.error(error);
      alert("Could not load applications");
    }
  };

  if (!isLoggedIn) {
    return (
      <div className="min-vh-100 bg-light d-flex align-items-center">
        <div className="container">
          <div className="row justify-content-center">
            <div className="col-md-5">
              <div className="card shadow-lg border-0">
                <div className="card-body p-5">
                  <h2 className="text-center mb-2">Recruitment Platform</h2>
                  <p className="text-center text-muted mb-4">
                    Login to manage jobs and applications
                  </p>

                  <label className="form-label">Email</label>
                  <input
                    type="email"
                    className="form-control mb-3"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                  />

                  <label className="form-label">Password</label>
                  <input
                    type="password"
                    className="form-control mb-4"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                  />

                  <button className="btn btn-primary w-100" onClick={login}>
                    Login
                  </button>

                  <div className="alert alert-info mt-4 mb-0">
                    Demo login: test@test.com / Test123!
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-vh-100 bg-light">
      <nav className="navbar navbar-dark bg-dark px-4">
        <span className="navbar-brand mb-0 h1">Recruitment Platform</span>

        <div>
          <button className="btn btn-outline-light me-2" onClick={loadApplications}>
            View Applications
          </button>

          <button className="btn btn-danger" onClick={logout}>
            Logout
          </button>
        </div>
      </nav>

      <div className="container py-5">
        <div className="mb-5">
          <h1 className="fw-bold">Available Jobs</h1>
          <p className="text-muted">
            Browse open positions and apply as a candidate.
          </p>
        </div>

        {showApplications && (
          <div className="card shadow-sm border-0 mb-5">
            <div className="card-body">
              <h3 className="mb-3">Applications Dashboard</h3>

              <table className="table table-hover">
                <thead className="table-dark">
                  <tr>
                    <th>ID</th>
                    <th>Job</th>
                    <th>Candidate ID</th>
                    <th>Status</th>
                  </tr>
                </thead>

                <tbody>
                  {applications.map((app) => (
                    <tr key={app.id}>
                      <td>{app.id}</td>
                      <td>{app.job?.title}</td>
                      <td>{app.candidateId}</td>
                      <td>
                        <span className="badge bg-success">Submitted</span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>

              {applications.length === 0 && (
                <p className="text-muted">No applications found.</p>
              )}
            </div>
          </div>
        )}

        <div className="row">
          {jobs.map((job) => (
            <div className="col-md-4 mb-4" key={job.id}>
              <div className="card h-100 shadow-sm border-0">
                <div className="card-body d-flex flex-column">
                  <h5 className="card-title fw-bold">{job.title}</h5>

                  <p className="card-text text-muted">{job.description}</p>

                  <p>
                    <strong>Location:</strong> {job.location}
                  </p>

                  <p>
                    <strong>Salary:</strong> {job.salary} SEK
                  </p>

                  <button
                    className="btn btn-success mt-auto"
                    onClick={() => applyToJob(job.id)}
                  >
                    Apply
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>

        {jobs.length === 0 && (
          <div className="alert alert-warning">
            No jobs found. Add jobs from Swagger first.
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
